INSERT INTO nongsaro_farm_schedules (cntnts_no, crop_code, crop_name, farm_work_type, info_type_code, info_type_name, operation_name, start_month, start_period, end_month, end_period, duration_months, video_url, raw_data) VALUES ('30680', '210003', '화훼', '수국', '410002', '기상재해 및 예상되는 문제점', '<div class=''cnt-td'' style=''margin:3px;''><br /><span class=''txt-l''>· 꺾꽂이 실패 : 꺾꽂이 후 적온 유지(야간온도 21℃  이상, 주간온도 26℃  이하 유지), 습도 65~85% 유지<br />· 개화 유도 : 단일 및 저온조건에서 꽃눈분화 유도(야간온도 11~18℃  유지)<br />· 꽃눈부패 및 건조 : 저온처리에 앞서 잎솎기 처리와 살균제 처리, 저온처리 시 상대습도 20~60% 유지, 질소 수준을 낮춤)<br />· 개화 후 관리 : 출하 후에도 적절한 수분관리 중요, 실내온도 15~18℃ 유지, 반사광 및 그늘진 상태에서 수명 연장 됨</span></div>', '1', '상', '12', '하', NULL, NULL, '{"beginEra": "상", "beginMon": "1", "cntntsNo": "30680", "endEra": "하", "endMon": "12", "farmWorkFlag": "수국", "infoSeCode": "410002", "infoSeCodeNm": "기상재해 및 예상되는 문제점", "kidofcomdtySeCode": "210003", "kidofcomdtySeCodeNm": "화훼", "opertNm": "<div class=''cnt-td'' style=''margin:3px;''><br /><span class=''txt-l''>· 꺾꽂이 실패 : 꺾꽂이 후 적온 유지(야간온도 21℃  이상, 주간온도 26℃  이하 유지), 습도 65~85% 유지<br />· 개화 유도 : 단일 및 저온조건에서 꽃눈분화 유도(야간온도 11~18℃  유지)<br />· 꽃눈부패 및 건조 : 저온처리에 앞서 잎솎기 처리와 살균제 처리, 저온처리 시 상대습도 20~60% 유지, 질소 수준을 낮춤)<br />· 개화 후 관리 : 출하 후에도 적절한 수분관리 중요, 실내온도 15~18℃ 유지, 반사광 및 그늘진 상태에서 수명 연장 됨</span></div>", "reqreMonth": "36", "vodUrl": null}'::jsonb) ON CONFLICT (cntnts_no, operation_name, start_month) DO NOTHING;
